function LGpManager:Initialize()
	LxBaseMgr.Initialize(self)
	self._gameplayList = {}
end

function LGpManager:DoAfterInitialize()
	if not CS.IsWebGL() then
		self:InitStartManager()
	end
end

function LGpManager:InitStartManager()
	--战斗和挂机用的地方太多，先不修改这两个全局变量了
	gLFightManager = self:FindFightGp()
	gLFightIdleManager = self:FindFightIdleGp()
end

function LGpManager:Dispose()
	self:ClearAllGp()
	gLFightManager = nil
	gLFightIdleManager = nil
	LxBaseMgr.Dispose(self)
end
-----------------------------------------------------------------
function LGpManager:ClearAllGp()
	local gameplayList = self._gameplayList
	self._gameplayList = nil
	if not gameplayList then return end

	local len = #gameplayTypeList
	local mgr = nil

	local mgrType
	for k=len,1,-1 do
		mgrType = gameplayTypeList[k]
		mgr = gameplayList[mgrType]
		gameplayList[mgrType] = nil
		if mgr then
			mgr:Destroy()
		end
	end
end

-----------------------------------------------------------------
function LGpManager:DestroyGp(mgrType)
	local inst = self._gameplayList[mgrType]
	if not inst then
		return
	end
	self._gameplayList[mgrType] = nil
	inst:Destroy()
end

function LGpManager:IsGpInit(mgrType)
	local inst = self._gameplayList[mgrType]
	if inst then
		return true
	end
	return false
end

-----------------------------------------------------------------
function LGpManager:_InnerGetGp(mgrType)
	local inst = self._gameplayList[mgrType]
	if not inst then
		inst = LxRequire(fullNameMap[mgrType]):New()
		self._gameplayList[mgrType] = inst
		inst:Create()
		inst:InitStart()
	end
	return inst
end

